  console.log(greet('love'));
};

{
  "name": "typescript-service",
  "version": "1.0.0",
  "description": "A portable TypeScript service workspace",
  "main": "dist/index.js",
  "scripts": {
    "build": "tsc --outDir dist --rootDir src",
    "start": "node dist/index.js"
  },
  "dependencies": {
    "typescript": "^4.5.2"
  }
}

{
  "compilerOptions": {
    "target": "ES6",
    "module": "CommonJS",
    "strict": true,
    "esModuleInterop": true,
    "skipLibCheck": true,
    "forceConsistentCasingInFileNames": true,
    "outDir": "./dist",
    "rootDir": "./src"
  },
  "include": [
    "src/**/*"
  ]
}

// Entry point of the TypeScript service
import { greet } from './greet';

// Export callable function
export const runService = () => {
  console.log(greet('love'));
};

